// iter_1.mlir - TransformDialectCodegen strategy for
// main_dispatch_0_slow_memcpy (mobilenet f32 dispatch 0).
//
// Target: linalg.generic pure copy memref<224x224x3xf32> into a
// strided subview of memref<225x225x3xf32> (stride [675,3,1]).
// All three iterators are parallel (H, W, C).
//
// Hypothesis:
//   - Tile only the outer H dim via tile_using_forall [1, 0, 0] so each
//     workgroup strips a single H=1 row. Inside the tile the op is a
//     [1, 224, 3] elementwise copy. W*C = 672 f32 is contiguous on the
//     input (stride 672) and contiguous within one H row on the output
//     (stride [675, 3, 1] -> inner W*C is 672 contiguous).
//   - Vectorize the generic with vector_sizes [1, 224, 3]. Since 1*224*3
//     = 672, this produces one flat 672-lane vector.transfer_read/write
//     pair per H iteration.
//   - Target is RVV generic-rv64, VLEN=1024 bits, native_vector_size=128
//     bytes = 32 f32 per register. LLVM RVV lowering will fold the 672
//     vector into a vsetvli/vle32/vse32 strip-mined loop at LMUL=m4
//     (VL=128 elts -> 6 iters covering 672 elts -> 6 vle+vse pairs per
//     H row, no reduction backedges).
//
// IR is already in memref form at strategy entry (dispatch arrived
// post-bufferization), so we skip bufferize / eliminate_empty_tensors.

module attributes { transform.with_named_sequence } {

  // Full codegen strategy.
  transform.named_sequence @copy_strategy(%variant_op: !transform.any_op) {
    // Re-match the generic copy.
    %generic = transform.structured.match
        ops{["linalg.generic"]} in %variant_op
      : (!transform.any_op) -> !transform.any_op

    // Distribution tile (workgroup level) - strip H only.
    %tiled, %forall =
        transform.structured.tile_using_forall %generic
        tile_sizes [1, 0, 0]
      : (!transform.any_op) -> (!transform.any_op, !transform.any_op)
    transform.iree.populate_workgroup_count_region_using_num_threads_slice
        %forall : (!transform.any_op) -> ()

    // Vectorize the tiled generic with explicit sizes [1, 224, 3].
    transform.structured.vectorize %tiled vector_sizes [1, 224, 3]
      : !transform.any_op

    // Post-vectorize cleanup: drop unit-extent leading dims from the
    // resulting vector.transfer_* ops, canonicalize, CSE.
    %func = transform.structured.match ops{["func.func"]} in %variant_op
      : (!transform.any_op) -> !transform.any_op
    transform.apply_patterns to %func {
      transform.apply_patterns.vector.cast_away_vector_leading_one_dim
      transform.apply_patterns.canonicalization
    } : !transform.any_op
    transform.apply_cse to %func : !transform.any_op

    // Lower vector.transfer to 1-D transfers the RVV lowering expects.
    transform.apply_patterns to %func {
      transform.apply_patterns.vector.lower_masked_transfers
      transform.apply_patterns.vector.transfer_to_scf
          max_transfer_rank = 1 full_unroll = true
      transform.apply_patterns.vector.lower_shape_cast
    } : !transform.any_op

    // Reset translation_info to None - required by
    // LowerExecutableUsingTransformDialectPass (see SKILL.md).
    %none_info = transform.param.constant
        #iree_codegen.translation_info<pipeline = None>
      -> !transform.any_param
    transform.annotate %func "translation_info" = %none_info
      : !transform.any_op, !transform.any_param

    transform.yield
  }

  // Annotator - stamps the dispatch func with TransformDialectCodegen
  // and a reference to @copy_strategy.
  transform.named_sequence @annotate_copy_strategy(
      %generic: !transform.any_op {transform.readonly}) {
    %variant_op = transform.get_parent_op %generic
        {op_name = "hal.executable.variant"}
      : (!transform.any_op) -> !transform.any_op
    %funcs = transform.structured.match ops{["func.func"]} in %variant_op
      : (!transform.any_op) -> !transform.any_op
    %info = transform.param.constant
        #iree_codegen.translation_info<pipeline = TransformDialectCodegen
                                       codegen_spec = @copy_strategy>
      -> !transform.any_param
    transform.annotate %funcs "translation_info" = %info
      : !transform.any_op, !transform.any_param
    transform.yield
  }

  // Matcher - selects the linalg.generic in this variant. The dispatch
  // contains exactly one linalg.generic, so a name match is sufficient.
  transform.named_sequence @match_copy(
      %op: !transform.any_op {transform.readonly}) -> (!transform.any_op) {
    transform.match.operation_name %op ["linalg.generic"]
      : !transform.any_op
    transform.yield %op : !transform.any_op
  }

  // Entry point - library(-dir) flag looks for @__kernel_config.
  transform.named_sequence @__kernel_config(
      %variant_op: !transform.any_op {transform.consumed})
    -> !transform.any_op {
    %res = transform.foreach_match in %variant_op
        @match_copy -> @annotate_copy_strategy
      : (!transform.any_op) -> (!transform.any_op)
    transform.yield %res : !transform.any_op
  }
}

